create table if not exists public.casino_domino_hands(room_id uuid not null references public.casino_rooms(id) on delete cascade,profile_id uuid not null references public.casino_player_profiles(id) on delete cascade,seat smallint not null check(seat between 0 and 3),tiles jsonb not null default '[]',primary key(room_id,profile_id),unique(room_id,seat));
alter table public.casino_domino_hands enable row level security;revoke all on public.casino_domino_hands from anon,authenticated;
create or replace function public.domino_pips(p_tiles jsonb) returns integer language sql immutable as $$select coalesce(sum(split_part(v,'-',1)::int+split_part(v,'-',2)::int),0)::int from jsonb_array_elements_text(p_tiles) t(v);$$;

create or replace function public.get_online_domino_state(p_room_id uuid) returns jsonb language plpgsql stable security definer set search_path=public as $$declare v_profile uuid:=public.current_casino_profile_id();v_state jsonb;v_hand jsonb;v_seat int;v_counts jsonb;begin if not exists(select 1 from public.casino_room_members where room_id=p_room_id and profile_id=v_profile) then raise exception 'Room membership required';end if;select game_state into v_state from public.casino_rooms where id=p_room_id and game_type='domino';select tiles,seat into v_hand,v_seat from public.casino_domino_hands where room_id=p_room_id and profile_id=v_profile;select coalesce(jsonb_object_agg(seat,jsonb_array_length(tiles)),'{}'::jsonb) into v_counts from public.casino_domino_hands where room_id=p_room_id;return jsonb_build_object('state',coalesce(v_state,'{}'::jsonb),'hand',coalesce(v_hand,'[]'::jsonb),'seat',v_seat,'hand_counts',v_counts);end;$$;

create or replace function public.start_online_domino(p_room_id uuid,p_mode text default 'partners',p_target integer default 100) returns void language plpgsql security definer set search_path=public as $$declare v_tiles text[]:='{}';v_tmp text;v_i int;v_j int;v_member record;v_profile uuid;v_round int:=1;v_scores jsonb:='{"team0":0,"team1":0,"p0":0,"p1":0,"p2":0,"p3":0}';v_starter int;v_old jsonb;begin if not public.is_casino_room_host(p_room_id) then raise exception 'Host only';end if;if p_mode not in('partners','pintintin') or p_target not between 25 and 1000 then raise exception 'Invalid configuration';end if;if (select count(*) from public.casino_room_members where room_id=p_room_id and seat is not null)<>4 then raise exception 'Four seated players are required';end if;select game_state into v_old from public.casino_rooms where id=p_room_id for update;if v_old->>'phase'='round-over' then v_round:=coalesce((v_old->>'round')::int,0)+1;v_scores:=v_old->'scores';v_starter:=(v_old->>'next_starter')::int;end if;for v_i in 0..6 loop for v_j in v_i..6 loop v_tiles:=array_append(v_tiles,v_i||'-'||v_j);end loop;end loop;for v_i in reverse array_length(v_tiles,1)..2 loop v_j:=1+floor(random()*v_i)::int;v_tmp:=v_tiles[v_i];v_tiles[v_i]:=v_tiles[v_j];v_tiles[v_j]:=v_tmp;end loop;delete from public.casino_domino_hands where room_id=p_room_id;for v_member in select m.profile_id,m.seat from public.casino_room_members m where m.room_id=p_room_id and m.seat is not null order by m.seat loop insert into public.casino_domino_hands(room_id,profile_id,seat,tiles) values(p_room_id,v_member.profile_id,v_member.seat,to_jsonb(v_tiles[v_member.seat*7+1:v_member.seat*7+7]));if v_round=1 and '6-6'=any(v_tiles[v_member.seat*7+1:v_member.seat*7+7]) then v_starter:=v_member.seat;end if;end loop;update public.casino_rooms set game_state=jsonb_build_object('kind','domino','phase','playing','mode',p_mode,'target',p_target,'round',v_round,'scores',v_scores,'chain','[]'::jsonb,'left',null,'right',null,'current_seat',v_starter,'last_player',null,'passes',0,'opening_required',v_round=1,'next_starter',v_starter,'message','Comienza la mano'),state_version=state_version+1,updated_at=now() where id=p_room_id;end;$$;

create or replace function public.play_online_domino(p_room_id uuid,p_tile text,p_end text) returns void language plpgsql security definer set search_path=public as $$declare v_profile uuid:=public.current_casino_profile_id();v_seat int;v_hand jsonb;v_state jsonb;v_a int:=split_part(p_tile,'-',1)::int;v_b int:=split_part(p_tile,'-',2)::int;v_left int;v_right int;v_chain jsonb;v_pa int;v_pb int;v_remaining int;v_points int;v_key text;v_score int;begin select h.seat,h.tiles,r.game_state into v_seat,v_hand,v_state from public.casino_domino_hands h join public.casino_rooms r on r.id=h.room_id where h.room_id=p_room_id and h.profile_id=v_profile for update of h,r;if not found or v_state->>'phase'<>'playing' then raise exception 'Game unavailable';end if;if v_seat<>(v_state->>'current_seat')::int then raise exception 'Not your turn';end if;if not v_hand ? p_tile then raise exception 'Tile not in hand';end if;v_chain:=v_state->'chain';if jsonb_array_length(v_chain)=0 then if coalesce((v_state->>'opening_required')::boolean,false) and p_tile<>'6-6' then raise exception 'The first hand must open with double six';end if;v_pa:=v_a;v_pb:=v_b;v_left:=v_pa;v_right:=v_pb;v_chain:=jsonb_build_array(v_pa||'-'||v_pb);else v_left:=(v_state->>'left')::int;v_right:=(v_state->>'right')::int;if p_end='left' and (v_a=v_left or v_b=v_left) then if v_b=v_left then v_pa:=v_a;v_pb:=v_b;else v_pa:=v_b;v_pb:=v_a;end if;v_left:=v_pa;v_chain:=jsonb_build_array(v_pa||'-'||v_pb)||v_chain;elsif p_end='right' and (v_a=v_right or v_b=v_right) then if v_a=v_right then v_pa:=v_a;v_pb:=v_b;else v_pa:=v_b;v_pb:=v_a;end if;v_right:=v_pb;v_chain:=v_chain||jsonb_build_array(v_pa||'-'||v_pb);else raise exception 'Tile does not fit that end';end if;end if;select coalesce(jsonb_agg(value),'[]'::jsonb) into v_hand from jsonb_array_elements(v_hand) where value#>>'{}'<>p_tile;update public.casino_domino_hands set tiles=v_hand where room_id=p_room_id and profile_id=v_profile;v_remaining:=jsonb_array_length(v_hand);v_state:=jsonb_set(v_state,'{chain}',v_chain);v_state:=jsonb_set(v_state,'{left}',to_jsonb(v_left));v_state:=jsonb_set(v_state,'{right}',to_jsonb(v_right));v_state:=jsonb_set(v_state,'{last_player}',to_jsonb(v_seat));v_state:=jsonb_set(v_state,'{passes}','0');if v_remaining=0 then select sum(public.domino_pips(tiles)) into v_points from public.casino_domino_hands where room_id=p_room_id;v_key:=case when v_state->>'mode'='partners' then 'team'||(v_seat%2) else 'p'||v_seat end;v_score:=coalesce((v_state->'scores'->>v_key)::int,0)+v_points;v_state:=jsonb_set(v_state,array['scores',v_key],to_jsonb(v_score),true);v_state:=jsonb_set(v_state,'{phase}',to_jsonb(case when v_score>=(v_state->>'target')::int then 'match-over' else 'round-over' end));v_state:=jsonb_set(v_state,'{next_starter}',to_jsonb(v_seat));v_state:=jsonb_set(v_state,'{message}',to_jsonb('Mano terminada: '||v_points||' puntos'));else v_state:=jsonb_set(v_state,'{current_seat}',to_jsonb((v_seat+1)%4));v_state:=jsonb_set(v_state,'{message}',to_jsonb('Ficha jugada'));end if;update public.casino_rooms set game_state=v_state,state_version=state_version+1,updated_at=now() where id=p_room_id;end;$$;

create or replace function public.pass_online_domino(p_room_id uuid) returns void language plpgsql security definer set search_path=public as $$declare v_profile uuid:=public.current_casino_profile_id();v_seat int;v_hand jsonb;v_state jsonb;v_tile text;v_a int;v_b int;v_left int;v_right int;v_passes int;v_last int;v_next int;v_winner int;v_low int:=9999;v_total int;v_value int;v_i int;v_key text;v_score int;begin select h.seat,h.tiles,r.game_state into v_seat,v_hand,v_state from public.casino_domino_hands h join public.casino_rooms r on r.id=h.room_id where h.room_id=p_room_id and h.profile_id=v_profile for update of h,r;if not found or v_seat<>(v_state->>'current_seat')::int then raise exception 'Not your turn';end if;v_left:=(v_state->>'left')::int;v_right:=(v_state->>'right')::int;for v_tile in select jsonb_array_elements_text(v_hand) loop v_a:=split_part(v_tile,'-',1)::int;v_b:=split_part(v_tile,'-',2)::int;if v_a in(v_left,v_right) or v_b in(v_left,v_right) then raise exception 'You have a playable tile';end if;end loop;v_passes:=coalesce((v_state->>'passes')::int,0)+1;if v_passes<4 then v_state:=jsonb_set(v_state,'{passes}',to_jsonb(v_passes));v_state:=jsonb_set(v_state,'{current_seat}',to_jsonb((v_seat+1)%4));v_state:=jsonb_set(v_state,'{message}',to_jsonb('Jugador pasa'));else v_last:=(v_state->>'last_player')::int;if v_state->>'mode'='pintintin' then for v_i in 0..3 loop select public.domino_pips(tiles) into v_value from public.casino_domino_hands where room_id=p_room_id and seat=v_i;if v_value<v_low then v_low:=v_value;v_winner:=v_i;end if;end loop;else v_next:=(v_last+1)%4;select public.domino_pips(tiles) into v_value from public.casino_domino_hands where room_id=p_room_id and seat=v_last;select public.domino_pips(tiles) into v_low from public.casino_domino_hands where room_id=p_room_id and seat=v_next;v_winner:=case when v_value<=v_low then v_last else v_next end;end if;select sum(public.domino_pips(tiles)) into v_total from public.casino_domino_hands where room_id=p_room_id;v_key:=case when v_state->>'mode'='partners' then 'team'||(v_winner%2) else 'p'||v_winner end;v_score:=coalesce((v_state->'scores'->>v_key)::int,0)+v_total;v_state:=jsonb_set(v_state,array['scores',v_key],to_jsonb(v_score),true);v_state:=jsonb_set(v_state,'{phase}',to_jsonb(case when v_score>=(v_state->>'target')::int then 'match-over' else 'round-over' end));v_state:=jsonb_set(v_state,'{next_starter}',to_jsonb(v_winner));v_state:=jsonb_set(v_state,'{message}',to_jsonb('Tranca: '||v_total||' puntos'));end if;update public.casino_rooms set game_state=v_state,state_version=state_version+1,updated_at=now() where id=p_room_id;end;$$;

revoke all on function public.domino_pips(jsonb),public.get_online_domino_state(uuid),public.start_online_domino(uuid,text,integer),public.play_online_domino(uuid,text,text),public.pass_online_domino(uuid) from public;
grant execute on function public.get_online_domino_state(uuid),public.start_online_domino(uuid,text,integer),public.play_online_domino(uuid,text,text),public.pass_online_domino(uuid) to authenticated;
notify pgrst,'reload schema';
